-- =====================================================
-- T-03: سرقة السوق (4 players, 1 mafioso)
-- =====================================================
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES (
  'T-03', 'سرقة', 'السوق',
  'عم شوقي تاجر أقمشة في السوق أبو العلا، الصبح فتح المحل لقى مخزنه اللي ورا المحل مفتوح وأقمشة مستوردة بقيمة ٣٠٠ ألف جنيه اختفت. الباب الخلفي للمخزن اتفتح بالمفتاح ومفيش أي كسر. عم شوقي بيقول إنه بيسيب مفتاح المخزن في درج الكاشير وكل اللي شغالين معاه يعرفوا مكانه.',
  4, 1, 'وسام',
  'باب المخزن اتفتح بالمفتاح الأصلي — مفيش أي خدش أو كسر; الأقمشة اللي اتسرقت كلها الأنواع الغالية بس — حد كان عارف الفرق بين البضاعة; لقوا أثر عربية كارو كبيرة في الزنقة ورا المخزن; السرقة حصلت بين ١ و٤ الفجر حسب كلام حارس السوق; لقوا جوانتيات شغل ملقية جنب الباب الخلفي',
  'وسام — البياع الأول — كان آخر واحد قفل المحل يوم الخميس بالليل وشاف المفتاح في الدرج; لقوا إن وسام كان بيتكلم مع تاجر أقمشة في الغورية عنده محل بيشتري بضاعة من غير فواتير; وسام نسخ مفتاح المخزن عند مفتاحي في شارع جنبي — المفتاحي فاكره كويس; وسام كان متخانق مع عم شوقي على العمولة وبيقول "مش هسكت على حقي"; جار المخزن سمع صوت عربية كارو الساعة ٢ بالليل وسمع صوت حد بيرص حاجات',
  'تاجر الغورية اعترف إن وسام باعله أقمشة بـ١٢٠ ألف جنيه يوم الجمعة الصبح بدري; لقوا المفتاح المنسوخ في شنطة وسام في اللوكر بتاعه في المحل; وسام حوّل ٨٠ ألف جنيه لحساب مراته يوم السبت; صاحب الكارو قال إن وسام اتصل بيه الساعة ١٢ بالليل وطلب منه ينقل بضاعة; موبايل وسام كان في المنطقة الساعة ٢ الفجر مع إنه قال إنه كان في بيته في البيت',
  'وسام كان حاقد على عم شوقي عشان شغال معاه ٥ سنين ومش بياخد حقه في العمولة. نسخ مفتاح المخزن واتفق مع صاحب كارو يعرفه. يوم الخميس بالليل راح الساعة ١ الفجر، فتح المخزن بالمفتاح المنسوخ، شال الأقمشة الغالية على الكارو وودّاها لمخزن صاحبه في الغورية. باع البضاعة بنص تمنها وحوّل الفلوس لحساب مراته.',
  'عم شوقي — صاحب المحل — كان عليه ديون لتاجر كبير وناس بتقول ممكن يكون دبّر السرقة عشان التأمين; فوزي — الحمّال اللي بيشتغل في السوق — كان بيدخل المخزن يرص البضاعة ويعرف مكان كل حاجة ومحتاج فلوس عشان جوازه; سهام — بنت عم شوقي اللي بتساعده في الحسابات — كانت عارفة مكان المفتاح وكانت محتاجة فلوس عشان مشروع أونلاين',
  'production_ready', 'ar-EG'
);

INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-03'), 'وسام', 1, 'البياع الأول في محل عم شوقي من ٥ سنين، بيعرف كل أنواع الأقمشة وأسعارها وبيقفل المحل لوحده أوقات كتير', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-03'), 'عم شوقي', 2, 'صاحب المحل، تاجر كبير  من ٣٠ سنة ومعروف في السوق كله، عنده ٣ محلات بس المحل ده أكبرهم', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-03'), 'فوزي', 3, 'حمّال السوق اللي بيشيل البضاعة ويرصها في المخزن، شاب من الصعيد عنده ٢٥ سنة وشغال في السوق من ٣ سنين', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-03'), 'سهام', 4, 'بنت عم شوقي، خريجة تجارة وبتساعد أبوها في حسابات المحل وبتيجي كل يوم الصبح', false);


-- =====================================================
-- T-04: سرقة الصيدلية (4 players, 1 mafioso)
-- =====================================================
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES (
  'T-04', 'سرقة', 'الصيدلية',
  'دكتور ماجد صاحب صيدلية كبيرة ، الصبح فتح الصيدلية لقى المخزن اللي فيه الأدوية الغالية مفتوح وأدوية بقيمة ٤٠٠ ألف جنيه اختفت — أغلبها أدوية سرطان وأنسولين وحقن مستوردة. باب المخزن اتفتح بالكود الإلكتروني ومفيش كسر. الكود ده مع ٣ أشخاص بس.',
  4, 1, 'نهى',
  'باب المخزن الإلكتروني اتفتح بالكود الصح من أول محاولة — مفيش أي محاولات غلط; الأدوية اللي اتسرقت كلها من النوع الغالي اللي ليه سوق سودا كبير; لقوا ثلاجة الأنسولين مفتوحة وواحد شال الأنسولين بكراتينه — يعني عارف إزاي يحافظ عليه; كاميرا الصيدلية كانت شغالة بس حد قلب الكاميرا الداخلية ناحية الحيطة; لقوا كيس بلاستيك حراري فاضي — من النوع اللي بيتحفظ فيه الأدوية في النقل',
  'نهى — الصيدلانية المساعدة — كانت آخر واحدة في الصيدلية يوم الأربعا وقفلت الساعة ١١ بالليل; نهى عندها كود المخزن عشان بتطلب الأدوية وبترصها; لقوا إن نهى كلمت واحد اسمه أبو عمرو معروف إنه بيشتري أدوية من السوق السودا; نهى قلبت الكاميرا الداخلية — لقوا بصمتها على الكاميرا; رسالة من نهى لأختها بتقول "بكرة هتلاقيني حليت مشكلة الفلوس"',
  'أبو عمرو — تاجر السوق السودا — اعترف إن نهى باعتله أدوية بـ١٥٠ ألف يوم الخميس الصبح; نهى اشترت عربية مستعملة يوم السبت ودفعت كاش; لقوا في شنطة نهى قفازات طبية ومفتاح ثلاجة نقل أدوية; نهى دخلت الصيدلية الساعة ١ بالليل — لقوا سجل الباب الإلكتروني بالكود بتاعها; جارة نهى شافتها راجعة البيت الساعة ٤ الفجر شايلة شنط تقيلة',
  'نهى كانت عارفة كل حاجة عن الأدوية الغالية ومكانها. يوم الأربعا بالليل قلبت الكاميرا الداخلية قبل ما تمشي ورجعت الساعة ١ بالليل بالكود. فتحت المخزن وشالت الأدوية الغالية في أكياس حرارية عشان تحافظ عليها. أخدت تاكسي لبيتها وخبّت البضاعة. الصبح باعت جزء كبير لأبو عمرو في السوق السودا بنص التمن.',
  'دكتور ماجد — صاحب الصيدلية — عليه أقساط كتيرة وناس بتقول إنه ممكن يكون عمل السرقة عشان التأمين ويبيع الأدوية مرتين; باسم — عامل التوصيل — كان بيوصل أدوية لبيوت وعنده أرقام زباين كتير وناس شاكة إنه بيبيع أدوية من تحت الترابيزة; ريهام — الكاشيرة — كانت بتغلط في الحسابات كتير وعم شوقي اللي جنب الصيدلية شافها بتحط حاجة في شنطتها مرة',
  'production_ready', 'ar-EG'
);

INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-04'), 'نهى', 1, 'صيدلانية مساعدة شغالة مع دكتور ماجد من ٣ سنين، بتعرف كل حاجة عن الأدوية ومعاها كود المخزن وبتقفل الصيدلية لوحدها أوقات', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-04'), 'دكتور ماجد', 2, 'صاحب الصيدلية، دكتور صيدلة خبرة ٢٠ سنة وعنده فرعين ، مسؤول عن طلب الأدوية الغالية', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-04'), 'باسم', 3, 'عامل التوصيل في الصيدلية، شاب عنده ٢٢ سنة بيوصل الأدوية للبيوت بالموتوسيكل وعارف عناوين الزباين', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-04'), 'ريهام', 4, 'الكاشيرة في الصيدلية، بتشتغل من سنة ونص وبتقبض الفلوس وبتعمل الفواتير', false);


-- =====================================================
-- T-07: سرقة الجيم (4 players, 1 mafioso)
-- =====================================================
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES (
  'T-07', 'سرقة', 'الجيم',
  'كابتن عادل صاحب جيم كبير ، الصبح فتح الجيم لقى أوضة الأجهزة المستوردة مفتوحة و٦ أجهزة تريدميل وكروس فيت بقيمة ٥٠٠ ألف جنيه اختفت. باب الأوضة كان مقفول بقفل إلكتروني وكود. الكود ده عند ٤ أشخاص بس. مفيش كسر والمصعد الخدمي اتستخدم بالليل.',
  4, 1, 'شريف',
  'القفل الإلكتروني اتفتح بكود صح الساعة ١:١٥ بالليل حسب سجل النظام; المصعد الخدمي اللي بينزل على الجراج اتستخدم ٤ مرات بين الساعة ١ و٣ بالليل; لقوا خدوش جديدة على أرضية المصعد من حاجات تقيلة اتسحبت; الأجهزة المسروقة كلها الماركات الغالية — حد كان عارف الفرق; كاميرا الجراج كانت مفصولة من الكهربا — حد شال الفيشة',
  'شريف — مدير الجيم — كان عنده مفتاح الجراج ومعاه كود أوضة الأجهزة; شريف اتصل بشركة نقل أجهزة رياضية قبل السرقة بيومين وسأل عن أسعار نقل ٦ أجهزة; لقوا إن شريف بيتكلم مع واحد اسمه أبو حسام عنده مخزن  بيشتري أجهزة رياضية مستعملة; شريف قفل الجيم يوم الأربعا بالليل الساعة ١١ وكان آخر واحد مشي; رسالة من شريف لمراته "متقلقيش الموضوع هيتحل الأسبوع ده"',
  'شركة النقل أكدت إن شريف طلب عربية يوم الخميس الساعة ١٢:٣٠ بالليل وقالهم ينزلوا الجراج; أبو حسام  عنده ٤ أجهزة من الجيم ولسه بيحاول يبيعهم وقال إن شريف باعهمله; سجل المصعد الخدمي بيقول إن الكود اللي اتستخدم هو كود شريف الشخصي; شريف سدد ديون بـ١٥٠ ألف جنيه يوم السبت; كاميرا الشارع صورت عربية نقل واقفة قدام مدخل الجراج الساعة ١ بالليل وواحد شبه شريف',
  'شريف كان عليه ديون كبيرة من مشروع فشل. يوم الخميس بعد ما الكل مشي، فصل كاميرا الجراج ورجع الساعة ١ بالليل. فتح أوضة الأجهزة بالكود واستخدم المصعد الخدمي ينزّل الأجهزة على الجراج واحدة واحدة. عربية النقل شحنت الأجهزة وودّتها لمخزن أبو حسام . شريف قبض الفلوس كاش وسدد جزء من ديونه.',
  'كابتن عادل — صاحب الجيم — كان بيفكر يقفل الجيم عشان خسران وناس شاكة إنه دبّر السرقة عشان التأمين; أمل — المحاسبة — كانت عارفة إن الجيم خسران وعندها كود أوضة الأجهزة وكانت محتاجة فلوس عشان ابنها المريض; سيف — المدرب — كان متخانق مع كابتن عادل على مرتبه واتسمع بيقول "هخلي الجيم ده يولع" وعنده كود أوضة الأجهزة كمان',
  'production_ready', 'ar-EG'
);

INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-07'), 'شريف', 1, 'مدير الجيم من ٤ سنين، مسؤول عن كل حاجة من الاشتراكات للصيانة ومعاه كل الأكواد والمفاتيح', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-07'), 'كابتن عادل', 2, 'صاحب الجيم، لاعب كمال أجسام سابق فتح الجيم من ١٠ سنين ومعروف ', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-07'), 'أمل', 3, 'محاسبة الجيم، ست في الأربعينات شغالة من ٣ سنين وبتعرف كل أرقام الجيم', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-07'), 'سيف', 4, 'مدرب اللياقة البدنية، شاب رياضي عنده ٢٨ سنة وبيفضل في الجيم لحد بالليل وعنده كود أوضة الأجهزة', false);


-- =====================================================
-- T-09: سرقة محل الموبايلات (4 players, 1 mafioso)
-- =====================================================
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES (
  'T-09', 'سرقة', 'محل الموبايلات',
  'عماد صاحب محل موبايلات كبير  الرئيسي، الصبح فتح المحل لقى الفاترينة الرئيسية فاضية و٣٥ موبايل سامسونج وآيفون بقيمة ٦٠٠ ألف جنيه اختفوا. الشاتر كان مقفول عادي بالكالون ومفيش كسر. الكاميرا الداخلية كانت شغالة بس حد حط سبراي أسود عليها.',
  4, 1, 'هيثم',
  'الشاتر اتفتح بمفتاح — مفيش أي علامة كسر أو خلع; الكاميرا الداخلية اتعملها سبراي أسود — حد كان عارف مكانها بالظبط; الفاترينة اتفتحت بمفتاحها الصغير مش بالكسر; لقوا علبة سبراي فاضية في سلة الزبالة اللي جنب المحل; الموبايلات المسروقة كلها الفلاجشيب — أغلى الأنواع — حد كان عارف إيه اللي يستاهل',
  'هيثم — الفني اللي بيصلح الموبايلات — كان آخر واحد في المحل يوم الثلاثاء وقفل الساعة ١٠ بالليل; هيثم عنده مفتاح الشاتر ومفتاح الفاترينة عشان ساعات بيفتح المحل لوحده; لقوا إن هيثم بيتكلم في جروب على تليجرام اسمه "بورصة الموبايلات" وعارض موبايلات بأسعار أقل من السوق; هيثم اشترى سبراي أسود من محل في روض الفرج قبل السرقة بيوم — كاميرا المحل صورته; رسالة صوتية من هيثم لواحد اسمه "أبو العز" بيقول "البضاعة جاهزة تعالى الصبح بدري"',
  'أبو العز — تاجر موبايلات  — عنده ٢٠ موبايل من اللي اتسرقوا ولسه بيبيع فيهم وقال إن هيثم جابهمله; هيثم حوّل ٢٠٠ ألف جنيه لحساب باسم أخوه يوم الخميس; لقوا بصمة هيثم على علبة السبراي اللي في الزبالة; هيثم بيقول إنه كان في بيته بس كاميرا العمارة اللي قصاد المحل صورته داخل الشارع الساعة ٢ بالليل; سيريال نمبر الموبايلات اللي عند أبو العز مطابق للي في جرد المحل',
  'هيثم كان عارف المحل من جوه وبره. يوم الثلاثاء بالليل عمل سبراي على الكاميرا الداخلية قبل ما يمشي. رجع الساعة ٢ بالليل بالمفتاح، فتح الشاتر والفاترينة وشال كل الموبايلات الغالية في شنطة ظهر كبيرة. قفل المحل ومشي وباع الموبايلات لأبو العز  الصبح بدري. حوّل الفلوس لحساب أخوه عشان مترتبطش باسمه.',
  'عماد — صاحب المحل — كان عنده خناقة مع شريكه القديم اللي سابه وناس بتقول إنه ممكن يكون عمل السرقة عشان ياخد فلوس التأمين ويبدأ من الأول; دعاء — البياعة — كانت بتحوّش فلوس عشان جوازها وناس لاحظوا إنها بتتأخر في تسليم الفلوس أوقات ومعاها مفتاح الفاترينة; رضا — عامل النظافة — كان بييجي بالليل ينضف المحل وعارف مكان الكاميرا والشاتر وكان محتاج فلوس عشان عملية لأمه',
  'production_ready', 'ar-EG'
);

INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-09'), 'هيثم', 1, 'فني تصليح الموبايلات في المحل من ٣ سنين، شاطر في شغله وبيعرف كل أنواع الموبايلات وعنده مفتاح الشاتر والفاترينة', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-09'), 'عماد', 2, 'صاحب المحل، تاجر موبايلات من ١٢ سنة وعنده فرع تاني في العتبة، راجل عملي وصارم', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-09'), 'دعاء', 3, 'البياعة في المحل من سنتين، بنت شاطرة في البيع وبتتعامل مع الزباين ومعاها مفتاح الفاترينة', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'T-09'), 'رضا', 4, 'عامل النظافة اللي بييجي كل يوم بالليل ينضف المحل، راجل غلبان عنده ٤٥ سنة وبيشتغل في ٣ محلات', false);
