-- K-02: 4 players, 1 mafioso — سوق 
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('K-02', 'خطف', 'الصايغ اللي اختفى', 'الحاج نبيل صايغ دهب معروف في السوق اختفى وهو قافل محله يوم الخميس بالليل. مراته اتصلت بيه الساعة ١٠ بالليل مردّش. المحل لقوه مقفول عادي والدهب في الخزنة. عربية النص نقل بتاعته واقفة في نفس مكانها بس المفتاح الاحتياطي مش موجود. السوق كان فاضي وقت ما اختفى ومحدش من التجار شاف حاجة. البوليس وصل الصبح لقى بقع زيت غريبة قدام المحل.', 4, 1, 'صبحي', 'واحد من الناس اللي بيقعد على القهوة قدام السوق قال إنه شاف عربية فان أبيض واقفة في الحارة الضلمة ورا المحل الساعة ٩ ونص; لقوا موبايل الحاج نبيل مكسور جوّه صندوق قمامة في آخر الحارة; صبحي بتاع محل البهارات اللي مقابل محل الدهب كان لسه في السوق في الوقت ده مع إنه بيقفل بدري; آخر مكالمة على موبايل الحاج نبيل كانت من رقم مجهول الساعة ٩ وربع وكلّمته ٣ دقايق', 'صبحي طلع عليه ديون كبيرة لناس في السوق وكان طلب من الحاج نبيل سلفة ورفض; الفان الأبيض اللي اتشاف في الحارة طلع مأجّر من محل تأجير  والهوية اللي اتأجّر بيها مزوّرة بس رقم التليفون اللي في العقد آخر ٤ أرقام زي رقم صبحي; كاميرا مسجد الحارة صوّرت صبحي وهو شايل شوال كبير وحاططه في الفان الساعة ١٠ إلا ربع; صبحي قال للبوليس إنه مشي من السوق الساعة ٨ بس كاميرا المسجد بتكذّبه', 'الفان لقوه متركون في جراج  وجوّاه حبل وشريط لاصق وبقايا أكل; صبحي عنده قريب ساكن في أوضة فوق الجراج ده ومحدش فيها دلوقتي; الرقم المجهول اللي اتصل بالحاج نبيل طلع من خط محمول مسجّل باسم أخت صبحي; واحد ساكن في العمارة اللي فوق الجراج قال إنه سمع صوت حد بيدق على باب حديد بالليل وصوت راجل بيقول "افتحولي"', 'صبحي كان مديون لناس خطيرة ومحتاج فلوس بأي طريقة. لما الحاج نبيل رفض يسلّفه فلوس قرّر يخطفه ويطلب فدية من أولاده. اتصل بيه من خط أخته وقاله "فيه زبون عايز يشتري دهب كتير تعال المحل تاني." لما الحاج نبيل رجع السوق صبحي خدّره بمنديل فيه مادة مخدّرة وحطّه في الفان. وصّله الجراج  وقفل عليه في الأوضة وبعت رسالة لابنه يطلب فدية من رقم مجهول.', 'نادر — تاجر توابل جنب المحل كان متخانق مع الحاج نبيل على إيجار المحل وهدّده قدام الناس إنه "هيخلّيه يندم"; سميحة — مراته التانية اللي محدش يعرف عنها وكانت بتضغط عليه يكتبلها شقة; أبو خالد — صاحب القهوة اللي في أول السوق كان بيراهن على الكورة وخسران فلوس كتير ومحتاج يسدّد بسرعة', 'production_ready', 'ar-EG');

-- K-04: 4 players, 1 mafioso — مدرسة 
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('K-04', 'خطف', 'بنت الناظر اللي ضاعت من المدرسة', 'ملك بنت الأستاذ رضا ناظر المدرسة الإعدادية بنات اختفت من المدرسة قبل ما الجرس يضرب بنص ساعة. المدرّسة بتاعتها قالت إنها طلبت تروح الحمام ومرجعتش. شنطتها في الفصل وموبايلها في الشنطة. باب المدرسة الخلفي اللي بيطل على الترعة كان مفتوح مع إنه المفروض يكون مقفول. البوليس لقى أثر جزمة كبيرة في الطين جنب الترعة ومنديل عليه ريحة غريبة.', 4, 1, 'هشام', 'المنديل اللي لقوه جنب الترعة طلع عليه مادة مخدّرة بتتباع في الصيدليات بروشتة; هشام الفرّاش بتاع المدرسة هو اللي عنده مفتاح الباب الخلفي والمفروض يقفله كل يوم الصبح; بنات في الفصل قالوا إن واحد كان واقف ورا سور المدرسة من ناحية الترعة وبيبص; أثر الجزمة اللي في الطين مقاس ٤٤ وده مقاس كبير; ملك قالت لصاحبتها الصبح إن "عمو هشام قالها فيه حد مستنيكي عند الباب ورا"', 'هشام طلع عنده ابن محتاج عملية ومش معاه فلوس وطلب سلفة من الناظر ورفض; كاميرا كشك الشاي اللي قدام المدرسة صوّرت موتوسيكل واقف جنب الترعة الساعة ١١ والسواق شبه هشام; هشام كان غايب عن المدرسة الحصة التالتة مع إنه المفروض يكون موجود; الباب الخلفي مكانش مكسور يعني اتفتح بالمفتاح; هشام هو اللي اشترى المادة المخدّرة من صيدلية قبلها بيومين والكاميرا صوّرته', 'الموتوسيكل اللي اتصوّر جنب الترعة طلع مسجّل باسم هشام; هشام عنده أرض صغيرة فيها عشّة في قرية ورا القرية ومحدش بيروحها; جارة العشّة قالت إنها سمعت صوت بنت صغيرة بتعيّط الضهر وراحت بصّت لقت الباب مقفول بجنزير; هشام بعد ما البوليس كلّمه غيّر كلامه ٣ مرات عن مكانه وقت الاختفاء', 'هشام كان محتاج فلوس ضروري لعملية ابنه. طلب من الناظر رضا سلفة كبيرة والناظر رفض وقاله "مش هينفع." هشام قرّر يخطف بنت الناظر ويطلب فدية. ساب الباب الخلفي مفتوح وقال لملك إن فيه حد من أهلها مستنيها. لما طلعت خدّرها بالمنديل وركّبها الموتوسيكل ووصّلها العشّة بتاعته. بعت رسالة للناظر من رقم مجهول يطلب ١٠٠ ألف جنيه.', 'سعاد — المدرّسة اللي سابت ملك تطلع من الفصل من غير ما تتأكّد إنها رجعت وكانت متخانقة مع الناظر على تقييم الأداء بتاعها; رجب — بتاع البوفيه اللي عنده مشاكل مع إدارة المدرسة وهدّد إنه "هيعمل حاجة تزعلهم"; إيناس — السكرتيرة اللي بتعرف كل أسرار المدرسة وعندها علاقة وحشة مع الناظر عشان نقلها من مكتبها', 'production_ready', 'ar-EG');

-- K-06: 4 players, 1 mafioso — مول 
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('K-06', 'خطف', 'ابن صاحب المول اللي طار', 'كريم ابن المهندس طارق صاحب مول كبير اختفى من المول يوم الجمعة بالليل. كان بيلعب في منطقة الألعاب لوحده بعد ما المول قفل. الحارس قال إنه شاف كريم آخر مرة الساعة ١٠ بالليل عند المصعد. كاميرات المول اتعطّلت من الساعة ٩ ونص بسبب "عطل فني." لقوا جزمة كريم الرياضية عند باب الطوارئ اللي بيطل على الجراج. أبوه بلّغ البوليس الساعة ١٢ بالليل لما مرجعش البيت.', 4, 1, 'عاطف', 'باب الطوارئ اللي لقوا جنبه الجزمة كان مفتوح من جوّه مع إنه بيتقفل أوتوماتيك; عاطف مدير الصيانة في المول هو المسؤول عن نظام الكاميرات وهو اللي بلّغ عن "العطل الفني"; واحد كان بيعدّي في الجراج شاف فان رمادي طالع بسرعة من الجراج الساعة ١٠ وربع; عاطف كان لسه في المول لحد الساعة ١٠ ونص مع إنه المفروض يمشي الساعة ٨; لقوا بقايا شيبسي من النوع اللي كريم بيحبه جنب باب الطوارئ', 'عاطف طلع عليه قضية نصب قديمة واتحبس سنتين ومحدش في المول يعرف; الفان الرمادي اللي اتشاف في الجراج طلع بتاع شركة توصيل بس الشركة قالت مفيش أي توصيلة ليها في المول يوم الجمعة; عاطف هو اللي قفل نظام الكاميرات يدوي الساعة ٩ ونص وقال "عطل" — سجلات النظام بتقول إنه اتقفل من كمبيوتر غرفة الصيانة; عاطف كان عارف إن المهندس طارق بيسيب ابنه في المول كل جمعة لوحده; عاطف اشترى شيبسي وعصير من سوبرماركت المول الساعة ٩ والفاتورة موجودة', 'الفان الرمادي لقوه في مزرعة في طريق صحراوي ومفتاح الفان عليه بصمات عاطف; جوّه الفان لقوا بطانية وحبل ومخدّة وريحة مخدّر خفيف; المزرعة طلعت بتاعة خال عاطف وفيها أوضة مقفولة بقفل جديد; جار المزرعة قال إنه شاف نور في الأوضة المقفولة بالليل وسمع صوت عيّل بيصرخ "عايز بابا"', 'عاطف كان محتاج فلوس كتير عشان يسدّد ديون قديمة. عرف إن المهندس طارق بيسيب ابنه في المول كل جمعة. قفل الكاميرات يدوي وقال عطل فني. استدرج كريم بالشيبسي لباب الطوارئ وقاله "أبوك مستنيك في العربية تحت." نزل بيه الجراج وركّبه الفان اللي كان مجهّزه. وصّله مزرعة خاله في المزرعة وقفل عليه. بعت رسالة للمهندس طارق من رقم مجهول يطلب مليون جنيه.', 'حسن — الحارس اللي كان نايم وقت ما كريم اختفى ومش عايز يعترف وعنده مشاكل مع إدارة المول على مرتّبه; داليا — مديرة منطقة الألعاب اللي سابت كريم لوحده ومشيت بدري وخايفة تتحاسب; يوسف — صاحب كافيه في المول ومتخانق مع المهندس طارق على الإيجار وهدّده قدام الناس إنه "هيخسّره حاجة غالية"', 'production_ready', 'ar-EG');

-- K-09: 4 players, 1 mafioso — قرية 
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('K-09', 'خطف', 'دكتور القرية اللي اختفى', 'الدكتور مجدي طبيب الوحدة الصحية في قرية صغيرة اختفى بعد ما قفل العيادة يوم التلات بالليل. كان بيركب موتوسيكله ويروّح زي كل يوم بس مراته قالت مجاش. الموتوسيكل لقوه على جنب الطريق الزراعي بين القرية والقرية اللي جنبها. خوذة الموتوسيكل على الأرض ومفتاح العيادة في الكونتاكت. الطريق ضلمة ومفيش كاميرات والناس بتنام بدري. القرية كلها اتلخبطت عشان الدكتور مجدي الوحيد اللي بيعالج الناس هنا.', 4, 1, 'عوض', 'لقوا آثار عجل تروسيكل جنب الموتوسيكل على الطريق الزراعي; عوض العطّار بتاع القرية كان رايح السوق بالتروسيكل بتاعه في نفس الوقت وقال إنه مشافش حاجة; واحد من الفلاحين قال إنه سمع صوت خناقة على الطريق الساعة ٩ ونص بس خاف يطلع يبص; لقوا نضارة الدكتور مجدي مكسورة على الأرض جنب الموتوسيكل; عوض اتصل بمراته الساعة ١٠ بالليل وقالها "متستنينيش هتأخّر" مع إنه قال إنه راجع من السوق', 'عوض طلع عنده خناقة قديمة مع الدكتور مجدي عشان الدكتور رفض يدّيه روشتات من غير كشف وقاله "إنت بتضر الناس بالأدوية اللي بتبيعها"; آثار التروسيكل على الطريق بتقول إنه وقف جنب الموتوسيكل مش عدّى وراح; عوض عنده غيط قديم فيه حظيرة مهجورة على بعد كيلو من مكان الاختفاء; الفلاح اللي سمع الخناقة قال إنه سمع صوت حد بيقول "اركب يا دكتور متعملش مشاكل"; عوض غيّر بنط التروسيكل اليوم اللي بعد الاختفاء', 'الحظيرة المهجورة بتاعة عوض لقوا فيها بطانية جديدة وأكل وجركن مية; جار عوض في الغيط قال إنه شاف نور جوّه الحظيرة بالليل مع إنها مهجورة من سنين; عوض اشترى حبل وشريط لاصق من السوق قبل الاختفاء بيوم والمحل عنده الفاتورة; التروسيكل القديم بتاع عوض لقوا فيه خيط من جلابية الدكتور مجدي معلّق في المسمار اللي في الصندوق ورا', 'عوض كان حاقد على الدكتور مجدي من يوم ما فضحه قدام القرية وقال إنه بيبيع أدوية غلط. الناس بطّلت تشتري من عوض والمحل وقع. قرّر ينتقم ويخطفه ويطلب فدية من أهله اللي في القاهرة. استنّاه على الطريق بالتروسيكل وقفله الطريق. لما الدكتور وقف عوض ضربه وكسر نضارته وركّبه التروسيكل غصب. وصّله الحظيرة المهجورة وربطه وقفل عليه. بعت رسالة لأخو الدكتور في القاهرة يطلب ٢٠٠ ألف جنيه.', 'حمدي — ابن العمدة اللي كان متخانق مع الدكتور عشان رفض يدّيه إجازة مرضية مزوّرة وقاله "هتندم يا دكتور"; أم سيد — الداية القديمة اللي الدكتور بطّل الناس يروحولها وخسرت رزقها وبتقول للناس "ربنا هيحاسبه"; شريف — سواق التوكتوك اللي بيوصّل الناس للعيادة وكان عايز الدكتور يدفعله أكتر ومتخانقين على الفلوس', 'production_ready', 'ar-EG');

