INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-02'), 'نبيل', 2, 'مسؤول المبيعات اللي بيجيب عملاء كتير وبيطلع معاهم يعاين شقق وعنده مفتاح المكتب', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-02'), 'هاني', 3, 'الموظف الجديد اللي بيتعلم الشغل ومسؤول عن الأرشيف والطباعة وبيقعد لوحده كتير في أوضة الملفات', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'B-02'), 'جمال', 4, 'حارس المكتب اللي بيقعد بالليل وعنده مفاتيح كل حاجة وبيعرف مين بيدخل ومين بيطلع', false);

