-- E-02: مستشفى  — 4 players, 1 mafioso
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language)
VALUES (
  'E-02',
  'اختفاء دليل',
  'أشعة المريض اللي طارت',
  'في مستشفى حكومي ، مريض دخل الطوارئ بعد حادثة سيارة وعملوله أشعة بيّنت إن فيه كسر في الجمجمة. الأشعة دي كانت الدليل الوحيد إن السواق كان بيسوق وهو سكران. قبل ما ملف المريض يتبعت للنيابة، الأشعة اختفت من الملف. أربع حد كانوا في الدور ده بالليل وعندهم وصول لمحطة التمريض اللي فيها الملفات.',
  4, 1, 'منار',
  'الأشعة كانت مطبوعة ومحطوطة في ملف المريض في محطة التمريض; الملف لسه موجود بس الأشعة مش فيه; كاميرا الممر بتوري إن الأربع حد دخلوا وخرجوا من محطة التمريض أكتر من مرة بالليل; مفيش حد غريب ظهر في الدور',
  'منار الممرضة طلبت من زميلتها تغطيلها نص ساعة وقالت "عندي مشوار سريع في الدور التاني"; الدكتور المناوب كتب في التقرير إن الأشعة موجودة الساعة ١١ بالليل; لوج الطابعة بيقول إن حد طبع صفحة واحدة من جهاز محطة التمريض الساعة ١:٣٠ الفجر; السواق اللي عمل الحادثة طلع قريب منار — ابن عمها',
  'بصمة منار اتلاقت على ضهر ورقة في سلة الزبالة — نفس حجم ورقة الأشعة; كاميرا الممر صورت منار وهي شايلة كيس أسود صغير الساعة ٢ الفجر ونزلت بيه السلم; منار اتصلت بابن عمها قبلها بساعة والمكالمة كانت ٨ دقايق; اتلاقت بقايا ورقة لامعة — زي ورق الأشعة — محروقة في جردل ورا المستشفى',
  'منار عرفت إن الأشعة هتورط ابن عمها في قضية قيادة تحت تأثير الكحول وممكن يتحبس. ابن عمها اتصل بيها وتوسّلها تساعده. منار استنت لحد ما زميلتها سابت المحطة، طلعت الأشعة من الملف، حطتها في كيس ونزلت حرقتها ورا المستشفى. كانت فاكرة إن حد هيفتكر إن الأشعة ضاعت في الزحمة.',
  'دكتور عصام المناوب كان بيراجع ملفات مرضى كتير بالليل وبصماته على كل الملفات عشان ده شغله; سهام الممرضة التانية كانت بتغطي لمنار وراحت نامت في أوضة الراحة نص ساعة وخايفة تقول عشان ده مخالفة; باسم عامل النظافة كان بيلف على الأدوار ودخل محطة التمريض ياخد كيس الزبالة ولمس الملفات من غير قصد',
  'production_ready', 'ar-EG'
);

-- E-04: نيابة  — 4 players, 1 mafioso
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language)
VALUES (
  'E-04',
  'اختفاء دليل',
  'محضر الشهادة اللي اتبلع',
  'في النيابة، كان فيه محضر شهادة شاهد رئيسي في قضية رشوة كبيرة ضد مسؤول في المحافظة. المحضر كان مكتوب بخط الإيد ومحطوط في ملف القضية في مكتب وكيل النيابة. الصبح لما جه يجهّز الملف للجلسة، لقى المحضر مش موجود. من غير الشهادة دي القضية هتتأجل وممكن تسقط. أربع حد كانوا في المكتب بالليل.',
  4, 1, 'شريف',
  'ملف القضية لسه موجود وفيه كل الورق التاني — المحضر بس هو اللي ناقص; مفتاح المكتب كان مع أربع حد — وكيل النيابة وتلات موظفين; الباب مكانش مكسور يعني حد فتحه بالمفتاح; الحارس قال إن التلات موظفين كانوا موجودين لحد الساعة ١٠ بالليل',
  'شريف كاتب التحقيق هو اللي كتب المحضر بإيده وكان عارف كل كلمة فيه; اتلاقت بصمات التلات موظفين على الملف — وده عادي عشان كلهم بيشتغلوا عليه; حد من الموظفين اتصل بيه رقم مجهول الساعة ٩ بالليل والمكالمة كانت ٢٠ دقيقة; المسؤول المتهم بالرشوة عنده صلة قرابة بواحد من الأربعة',
  'المكالمة المجهولة اللي الساعة ٩ طلعت من موبايل محامي المسؤول المتهم — والمكالمة كانت لشريف; كاميرا مدخل النيابة صورت شريف وهو خارج الساعة ١١ بالليل — ساعة بعد ما الكل مشي; شريف عنده قرابة بعيدة بالمسؤول المتهم — ابن خالة مراته; اتلاقت بقايا ورقة ممزقة في تواليت النيابة — عليها حبر أزرق نفس نوع القلم اللي المحضر اتكتب بيه',
  'شريف كان كاتب المحضر بإيده وعارف أهميته. محامي المسؤول المتهم اتصل بيه ولعب على وتر القرابة — ابن خالة مراته — ووعده بمبلغ كبير. شريف استنى لحد ما كل الموظفين مشيوا، رجع المكتب وطلع المحضر من الملف ومزقه في التواليت ونزله في المية. كان فاكر إن محدش هيشك فيه عشان هو اللي كتب المحضر أصلاً.',
  'نادية سكرتيرة وكيل النيابة كانت بتصور ملفات لنفسها عشان بتجهز لامتحان — وخايفة تقول عشان ممنوع; أمجد الكاتب التاني كان بيرتب ملفات قضايا تانية وقعد في المكتب لحد ١٠ بالليل عشان عليه شغل متأخر; هالة الموظفة كانت بتدور على ملف ضايع من قسمها ودخلت مكتب وكيل النيابة من غير إذن وخايفة تتكلم',
  'production_ready', 'ar-EG'
);

-- E-07: مكتب توثيق  — 4 players, 1 mafioso
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language)
VALUES (
  'E-07',
  'اختفاء دليل',
  'التوكيل اللي اختفى',
  'في مكتب توثيق ، واحد عمل توكيل رسمي لأخوه عشان يبيعله أرض. بعد ما التوكيل اتوثّق وقبل ما يتسلّم، النسخة الأصلية اختفت من دفتر التوثيق. من غير التوكيل الأصلي، أخوه مش هيقدر يبيع الأرض واللي زوّر توكيل تاني بداله هيعدّي. أربع حد كانوا في المكتب وقت ما التوكيل اختفى.',
  4, 1, 'فوزي',
  'دفتر التوثيق فيه كل التوكيلات بس التوكيل رقم ٣٧٤ — الصفحة اتقطعت بمشرط أو كاتر; المكتب فيه كاميرا بس كانت مطفية من يومين عشان عطل — والعطل ده كان معروف; أربع حد بس كانوا في المكتب بين الساعة ٢ و٤ العصر اللي هو وقت الاختفاء',
  'فوزي الموظف القديم كان قاعد لوحده في المكتب نص ساعة وقت ما زمايله طلعوا يصلّوا الضهر; فيه واحدة جت تسأل عن توكيل تاني وقعدت في المكتب ١٠ دقايق; اتلاقى كاتر صغير في درج مكتب فوزي — بس فوزي قال "ده بتاع الشغل"; صاحب الأرض اللي التوكيل باسمه اتصل بفوزي قبلها بيوم — والمكالمة كانت ١٢ دقيقة',
  'صاحب الأرض اللي اتصل بفوزي طلع عايز يمنع البيع عشان عنده مشكلة مع أخوه وعرض على فوزي فلوس; فوزي حوّل في حسابه مبلغ ١٥ ألف جنيه يوم ما التوكيل اختفى — من حساب مجهول; الكاتر اللي في درج فوزي عليه أثر حبر — نفس لون حبر دفتر التوثيق; شهادة الحارس بتقول إن فوزي طلع من المكتب يوم الحادثة ومعاه ورق في جيب الجاكيت بتاعه',
  'فوزي اتصل بيه صاحب الأرض — أخو اللي عمل التوكيل — اللي كان زعلان ومش عايز أخوه يبيع الأرض. عرض على فوزي ١٥ ألف جنيه مقابل إن التوكيل يختفي. فوزي استنى لحد ما زمايله طلعوا يصلّوا، قطع صفحة التوكيل من الدفتر بالكاتر، ولفها في جيبه وطلع بيها. كان فاكر إن حد هيفتكر إن الصفحة اتقطعت من زمان.',
  'عبير الموظفة الجديدة كانت بتراجع دفتر التوثيق عشان بتتعلم وبصماتها على صفحات كتير; وجدي الموظف التاني كان بيرتب الأدراج ولقى ورق قديم ورماه في الزبالة — وده خلاه يبان مريب; سعاد المراجعة كانت بتصور صفحات من الدفتر على موبايلها عشان تطابقها بسجل الكمبيوتر وخايفة تقول',
  'production_ready', 'ar-EG'
);

-- E-09: معمل تحاليل  — 4 players, 1 mafioso
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language)
VALUES (
  'E-09',
  'اختفاء دليل',
  'عينة الدم اللي ضاعت',
  'في معمل تحاليل خاص ، عينة دم مريض كانت هتثبت إنه اتسمم بمادة معينة — والتحليل ده كان هيورّط واحد من أقاربه. العينة كانت محطوطة في التلاجة الخاصة بالمعمل ومكتوب عليها اسم المريض ورقم القضية. الصبح لما الفني راح يشتغل عليها، لقى العينة مش موجودة. أربع حد كانوا في المعمل بالليل.',
  4, 1, 'رضا',
  'التلاجة اتفتحت بالكود — مفيش أثر كسر ولا عبث; باقي العينات كلها موجودة — عينة المريض ده بس اللي اختفت; سجل التلاجة الإلكتروني بيقول إنها اتفتحت ٣ مرات بالليل; الأربع حد كلهم كانوا عارفين إن العينة مهمة عشان الدكتور قال كده الصبح',
  'رضا فني المعمل الليلي هو اللي عنده كود التلاجة وبيفتحها كل يوم عادي; واحد من الأربعة اتصل بيه حد من بره المعمل الساعة ١٠ بالليل — المكالمة كانت ١٥ دقيقة; المريض اللي العينة بتاعته ضاعت — أبوه راجل أعمال كبير  ومعروف; فيه عينة تانية باسم مريض تاني مكانها اتغيّر في التلاجة — يعني حد فتح ولعب في الترتيب',
  'المكالمة اللي الساعة ١٠ بالليل طلعت من موبايل أبو المريض — وكانت لرضا; رضا حوّل في حسابه ٢٠ ألف جنيه من يومين — من حساب شركة أبو المريض; كاميرا المعمل من بره بتوري إن رضا خرج الساعة ١٢ بالليل ومعاه كيس أحمر صغير — شبه أكياس العينات; سجل التلاجة بيقول إن الفتحة التالتة كانت الساعة ١١:٤٥ — ورضا قال إنه فتحها مرتين بس',
  'رضا اتصل بيه أبو المريض — اللي عارف إن التحليل هيثبت إن ابنه اتسمم وهيورطه هو شخصياً. أبو المريض عرض على رضا ٢٠ ألف جنيه مقابل إن العينة تختفي. رضا استنى لحد ما زمايله انشغلوا، فتح التلاجة وطلع العينة وحطها في كيس ونزل بيها. كبّها في الصرف بره المعمل. كان فاكر إن حد هيفتكر إن العينة اتلفت لوحدها.',
  'دكتورة نهى المشرفة كانت بتراجع نتايج تحاليل تانية وفتحت التلاجة مرة عشان تطلع عينات — وده يفسر الفتحة الأولى; عماد فني الصيانة كان بيصلح جهاز في المعمل وقعد لحد ١ بالليل وكان قريب من التلاجة بس ماكانش عنده الكود; سلمى موظفة الاستقبال كانت بتعمل جرد ورقي للعينات وكتبت إن العينة موجودة الساعة ٩ بالليل — يعني اختفت بعد كده',
  'production_ready', 'ar-EG'
);

